+// ---------------------------------------------------------------------------
+// Engine slot table — maps integer handles to Engine pointers
+// ---------------------------------------------------------------------------
+const MAX_ENGINES = 16;
+var engine_slots: [MAX_ENGINES]?*turboquant.Engine = [_]?*turboquant.Engine{null} ** MAX_ENGINES;
